const response = $input.first().json;
const content = response.content?.[0]?.text || '[]';
let assessments;
try {
  const jsonMatch = content.match(/\[.*\]/s);
  assessments = JSON.parse(jsonMatch[0]);
} catch(e) {
  return [{ json: { error: 'parse_failed' } }];
}
return assessments.map(a => ({ json: a }));
